<template>
  <div class="code-review">
    <div class="page-header">
      <div>
        <h2 class="page-title">智能代码审查</h2>
        <p class="page-subtitle">AI 自动分析代码质量、检测 Bug 和安全漏洞</p>
      </div>
    </div>

    <el-row :gutter="24">
      <!-- 提交审查 -->
      <el-col :xs="24" :sm="24" :md="14">
        <div class="cr-card-main">
          <div class="cr-card-header">
            <i class="el-icon-document"></i>
            <span>提交代码审查</span>
          </div>
          <el-form :model="form" label-width="60px">
            <el-form-item label="标题">
              <el-input v-model="form.title" placeholder="给这次审查起个标题" class="cr-input" />
            </el-form-item>
            <el-form-item label="语言">
              <el-select v-model="form.language" class="cr-select">
                <el-option label="Java" value="java" />
                <el-option label="Python" value="python" />
                <el-option label="JavaScript" value="javascript" />
                <el-option label="TypeScript" value="typescript" />
                <el-option label="Go" value="go" />
                <el-option label="C++" value="cpp" />
                <el-option label="SQL" value="sql" />
              </el-select>
            </el-form-item>
            <el-form-item label="代码">
              <code-editor v-model="form.codeContent" :language="form.language" />
            </el-form-item>
            <el-form-item>
              <el-button type="primary" :loading="submitting" class="cr-submit-btn" @click="handleSubmit" :disabled="!form.codeContent">
                <i class="el-icon-upload2"></i>
                {{ submitting ? '提交中...' : '提交审查' }}
              </el-button>
            </el-form-item>
          </el-form>
        </div>
      </el-col>

      <!-- 审查历史 -->
      <el-col :xs="24" :sm="24" :md="10">
        <div class="cr-card-side">
          <div class="cr-card-header">
            <i class="el-icon-clock"></i>
            <span>审查历史 ({{ displayReviews.length }})</span>
          </div>

          <div v-if="displayReviews.length === 0" class="empty-state">
            <div class="empty-icon">📝</div>
            <p>暂无审查记录</p>
          </div>

          <div v-else class="review-list">
            <div v-for="item in displayReviews" :key="item.id" class="review-item" @click="$router.push(`/code-review/${item.id}`)">
              <div class="review-top">
                <span class="review-title">{{ item.title }}</span>
                <el-tag :type="statusTag(item.status)" size="mini" effect="plain" class="review-status">
                  {{ statusText(item.status) }}
                </el-tag>
              </div>
              <div class="review-mid">
                <span class="review-lang">{{ item.language }}</span>
                <span v-if="item.qualityScore != null" class="review-score" :class="scoreClass(item.qualityScore)">
                  <i class="el-icon-star-on"></i> {{ item.qualityScore }}
                </span>
              </div>
              <div class="review-bottom">
                <span v-if="item.bugCount != null" class="review-bugs">
                  <i class="el-icon-warning"></i> {{ item.bugCount }} bugs
                </span>
                <span class="review-time">{{ formatTime(item.createTime) }}</span>
              </div>
            </div>
          </div>
        </div>
      </el-col>
    </el-row>

    <!-- 轮询状态对话框 -->
    <el-dialog title="AI 审查中" :visible.sync="showPolling" :close-on-click-modal="false" width="380px" top="30vh" custom-class="polling-dialog">
      <div class="polling-content">
        <el-progress type="circle" :percentage="pollingProgress" :stroke-width="8" :status="pollingStatus" />
        <p class="polling-text">{{ pollingMessage }}</p>
      </div>
    </el-dialog>
  </div>
</template>

<script>
import CodeEditor from '../components/CodeEditor.vue';
import { codeReviewApi } from '../api';
import { mockReviews, fallbackArray } from '../mock';

export default {
  name: 'CodeReview',
  components: { CodeEditor },
  data() {
    return {
      form: { title: '', language: 'java', codeContent: '' },
      submitting: false,
      reviews: [],
      showPolling: false,
      pollingProgress: 0,
      pollingMessage: '正在提交审查请求...',
      pollingStatus: 'warning',
      pollingTimer: null,
      currentReviewId: null
    };
  },
  computed: {
    displayReviews() {
      return fallbackArray(this.reviews, mockReviews);
    }
  },
  created() { this.loadReviews(); },
  beforeDestroy() { this.stopPolling(); },
  methods: {
    async loadReviews() {
      try {
        const res = await codeReviewApi.getList({ page: 1, pageSize: 20 });
        if (res.code === 200) this.reviews = (res.data && res.data.list) || [];
      } catch {}
    },
    async handleSubmit() {
      if (!this.form.title || !this.form.codeContent) {
        this.$message.warning('请填写标题和代码内容');
        return;
      }
      this.submitting = true;
      try {
        const res = await codeReviewApi.submit(this.form);
        if (res.code === 200) {
          this.$message.success('提交成功，AI 审查中...');
          this.form.codeContent = '';
          this.currentReviewId = res.data.id;
          this.startPolling(res.data.id);
          this.loadReviews();
        }
      } finally {
        this.submitting = false;
      }
    },
    startPolling(id) {
      this.showPolling = true;
      this.pollingProgress = 10;
      this.pollingMessage = '等待处理中...';
      this.pollingStatus = 'warning';
      this.stopPolling();

      this.pollingTimer = setInterval(async () => {
        try {
          const res = await codeReviewApi.getStatus(id);
          if (res.code === 200) {
            const status = res.data.status;
            if (status === 'PROCESSING') {
              this.pollingProgress = 50;
              this.pollingMessage = 'AI 正在审查代码...';
              this.pollingStatus = 'warning';
            } else if (status === 'COMPLETED') {
              this.pollingProgress = 100;
              this.pollingMessage = '审查完成！';
              this.pollingStatus = 'success';
              setTimeout(() => {
                this.showPolling = false;
                this.$router.push(`/code-review/${id}`);
              }, 1000);
              this.stopPolling();
            } else if (status === 'FAILED') {
              this.pollingProgress = 100;
              this.pollingMessage = '审查失败';
              this.pollingStatus = 'exception';
              setTimeout(() => this.showPolling = false, 2000);
              this.stopPolling();
              this.loadReviews();
            } else {
              this.pollingProgress = 20;
              this.pollingMessage = '排队等待中...';
            }
          }
        } catch {
          this.stopPolling();
          this.showPolling = false;
        }
      }, 3000);
    },
    stopPolling() {
      if (this.pollingTimer) {
        clearInterval(this.pollingTimer);
        this.pollingTimer = null;
      }
    },
    statusText(s) { const m = { PENDING: '等待', PROCESSING: '审查中', COMPLETED: '已完成', FAILED: '失败' }; return m[s] || s; },
    statusTag(s) { const m = { PENDING: 'info', PROCESSING: 'warning', COMPLETED: 'success', FAILED: 'danger' }; return m[s] || 'info'; },
    scoreClass(s) {
      if (s >= 85) return 'score-high';
      if (s >= 70) return 'score-mid';
      return 'score-low';
    },
    formatTime(t) {
      if (!t) return '';
      const d = new Date(t);
      return `${d.getMonth()+1}/${d.getDate()} ${String(d.getHours()).padStart(2,'0')}:${String(d.getMinutes()).padStart(2,'0')}`;
    }
  }
};
</script>

